{
    // --- BEGIN: user implements ---
    printf("tkl_ble_gatts_value_notify called\n");

    if (preinit_only_onece == 0) {
        printf("BLE stack not initialized\n");
        return OPRT_COM_ERROR;
    }

    if (p_data == NULL || length == 0) {
        printf("Invalid notification data\n");
        return OPRT_INVALID_PARM;
    }

	gatts_notify_data_t notify_data;
    notify_data.attr_handle = char_handle;
    notify_data.value = p_data;
    notify_data.value_len = length;

	if (bt_manager_gatt_server_send_notify(&notify_data) != 0) {
        printf("Failed to send notification\n");
        return OPRT_COM_ERROR;
    }

    printf("Notification sent successfully\n");
    return OPRT_OK;
    // --- END: user implements ---
}

