static void bt_tuya_gatt_connection_cb(char *addr, gatts_connection_event_t event, int conn_handle)
{
    printf("GATT connection event: %d, addr: %s, conn_handle: %d\n", event, addr, conn_handle);

    if (g_gap_cb) {
        TKL_BLE_GAP_PARAMS_EVT_T evt;
        memset(&evt, 0, sizeof(evt));

        if (event == BT_GATT_CONNECTION) {
            evt.type = TKL_BLE_GAP_EVT_CONNECT;
            evt.result = OPRT_OK;
            evt.gap_event.connect.role = TKL_BLE_ROLE_SERVER;
			evt.conn_handle = conn_handle;
			g_gap_cb(&evt);
        } else if (event == BT_GATT_DISCONNECT) {
            evt.type = TKL_BLE_GAP_EVT_DISCONNECT;
            evt.result = OPRT_OK;
            evt.gap_event.disconnect.role = TKL_BLE_ROLE_SERVER;
			g_gap_cb(&evt);
        }
    }
}

static void bt_tuya_gatt_char_write_cb(gatts_char_write_req_t *char_write)
{
	int ret = 0;
    if (char_write && g_gatt_cb) {
        TKL_BLE_GATT_PARAMS_EVT_T evt;
        memset(&evt, 0, sizeof(TKL_BLE_GATT_PARAMS_EVT_T));
        evt.type = TKL_BLE_GATT_EVT_WRITE_REQ;
        // evt.conn_handle = char_write->conn_handle;
        evt.gatt_event.write_report.char_handle = char_write->attr_handle;
        evt.gatt_event.write_report.report.length = char_write->value_len;
        evt.gatt_event.write_report.report.p_data = char_write->value;
        g_gatt_cb(&evt);
		if (char_write->need_rsp) {
			gatts_write_rsp_t data;
			data.trans_id = char_write->trans_id;
			data.attr_handle = char_write->attr_handle;
			data.state = BT_GATT_SUCCESS;
			ret = bt_manager_gatt_server_send_write_response(&data);
			if (ret != 0)
				WMG_DEBUG("send write response failed!\n");
			else
				WMG_DEBUG("send write response success!\n");
		}
    }
}

